SELECT i.product_id AS productId, SUM(i.count) AS totalSaleCount FROM erp_sale_out_items i INNER JOIN erp_sale_out o ON i.out_id = o.id WHERE i.deleted = 0 AND o.deleted = 0 AND o.out_time >= #{startTime} AND o.out_time <= #{endTime}
AND i.product_id IN
#{id}
GROUP BY i.product_id

SELECT i.product_id AS productId, sup.name AS supplierName, i.product_price AS productPrice, pin.in_time AS inTime FROM erp_purchase_in_items i INNER JOIN erp_purchase_in pin ON i.in_id = pin.id INNER JOIN erp_supplier sup ON pin.supplier_id = sup.id WHERE i.deleted = 0 AND pin.deleted = 0 AND sup.deleted = 0 AND pin.in_time >= #{startTime} AND pin.in_time <= #{endTime}
AND i.product_id IN
#{id}
ORDER BY pin.in_time DESC
